frappe.ui.form.on("Lead", {
    validate: function(frm) {
        if (frappe.session.user === "Administrator") return;

        const fieldsToCheck = [
            { field: "email_id", label: "email" },
            { field: "mobile_no", label: "mobile number" },
            { field: "phone", label: "phone number" }
        ];

        const checkDuplicate = async () => {
            for (let item of fieldsToCheck) {
                const value = frm.doc[item.field];
                if (value) {
                    const res = await frappe.call({
                        method: "frappe.client.get_list",
                        args: {
                            doctype: "Lead",
                            filters: [
                                ["name", "!=", frm.doc.name],
                                [item.field, "=", value]
                            ],
                            fields: ["name"],
                            limit: 1
                        }
                    });
                    if (res.message && res.message.length > 0) {
                        const existing = res.message[0].name;
                        frappe.throw(
                            `A Lead with this ${item.label} already exists: 
                            <a href="/app/lead/${existing}" target="_blank">${existing}</a>`
                        );
                    }
                }
            }
        };

        return checkDuplicate(); // Important for async validation
    }
});

frappe.listview_settings['Lead'] = {
    add_fields: ["lead_temperature", "job_title"],

    formatters: {
        job_title(val, d, f, data) {
            // Combine Lead ID and Job Title, and add colored temperature
            let temp_color = {
                "Hot": "red",
                "Warm": "orange",
                "Cold": "blue",
                "Lost": "gray"
            }[data.lead_temperature] || "gray";
            let temp_label = data.lead_temperature
                ? `<span class="indicator-pill ${temp_color}">${__(data.lead_temperature)}</span>`
                : "";

            return `<span>${data.name} - ${val} ${temp_label}</span>`;
        }
    }
};

