frappe.ui.form.on('Lead', {
    refresh(frm) {
        // Wait for buttons to fully render
        setTimeout(() => {
            // 1️⃣ Remove existing duplicate buttons
            const actionItems = document.querySelectorAll('a.dropdown-item');
            actionItems.forEach((item) => {
                const text = item.innerText.trim();
                if (text === 'Add to Prospect' || text === 'Add to Opportunity') {
                    item.remove();  // Remove duplicate if it exists
                }
            });

            // 2️⃣ Add "Add to Opportunity" button only once
            if (!frm._opportunity_button_added) {
                frm.page.add_action_item('Add to Opportunity', function () {
                    frappe.new_doc('Opportunity', {
                        opportunity_from: 'Lead',
                        party_name: frm.doc.name,
                        contact_email: frm.doc.email_id,
                        contact_person: frm.doc.contact_person,
                        lead: frm.doc.name // optional if you want to link the lead
                    });
                });
                frm._opportunity_button_added = true;
            }

        }, 500); // Delay to ensure original buttons load
    }
});

frappe.ui.form.on('Lead', {
    refresh(frm) {
        // Try both methods: native and DOM-based, after short delay
        setTimeout(() => {
            // 1. ERPNext method (recommended if button was added via add_custom_button)
            frm.remove_custom_button('Add to Prospect');

            // 2. Also check toolbar DOM as fallback
            const allButtons = document.querySelectorAll('.btn');
            allButtons.forEach((btn) => {
                if (btn.innerText.trim() === 'Add to Prospect') {
                    btn.style.display = 'none'; // Or btn.remove();
                    console.log('✅ Removed Add to Prospect button from toolbar');
                }
            });

            // 3. As extra cleanup, clear any leftover custom buttons
            frm.clear_custom_buttons();

        }, 500); // Allow time for UI to finish rendering
    }
});

frappe.ui.form.on('Quotation', {
    refresh(frm) {
        // Wait for the timeline to render
        setTimeout(() => {
            // Check if button already exists to prevent duplication
            if (frm.page && !frm.whatsapp_button_added) {
                const timeline = frm.timeline.wrapper;

                // Find the "+ New Email" button
                const emailButton = timeline.find('button:contains("New Email")');

                if (emailButton.length > 0) {
                    // Create the WhatsApp button
                    const whatsappBtn = $(`<button class="btn btn-secondary btn-sm ml-2">+ WhatsApp</button>`);

                    // Add click functionality
                    whatsappBtn.on('click', () => {
                        frappe.msgprint("WhatsApp button clicked!");
                        // Optionally, add your logic to open a WhatsApp web/send message/etc.
                    });

                    // Insert it after the "+ New Email" button
                    emailButton.after(whatsappBtn);
                    frm.whatsapp_button_added = true; // Prevent re-adding
                }
            }
        }, 500); // Wait for the timeline to load
    }
});

