frappe.ui.form.on('Lead', {
    refresh: function(frm) {
        frm.events.add_custom_buttons(frm);
    },

    add_custom_buttons: function(frm) {
        setTimeout(() => {
            const timeline_area = frm.timeline?.wrapper;
            if (!timeline_area || frm.timeline.custom_buttons_added) return;

            const email_btn = timeline_area.find('.btn:contains("New Email")');
            if (email_btn.length === 0) return;

            const full_name = frappe.user.full_name();

            // WhatsApp button
            const whatsapp_btn = $(`<button class="btn btn-sm btn-success ml-2">
                <i class="fa fa-whatsapp"></i> WhatsApp
            </button>`).on('click', () => {
                // Always get latest phone info from DB just before posting comment
                frappe.db.get_doc('Lead', frm.doc.name).then(doc => {
                    let phone = doc.phone || doc.mobile_no || "Not available";
                    let message = `🟢 <b>${full_name}</b> contacted via WhatsApp at <b>${phone}</b>.`;
                    frappe.call({
                        method: "frappe.client.insert",
                        args: {
                            doc: {
                                doctype: "Comment",
                                comment_type: "Comment",
                                reference_doctype: "Lead",
                                reference_name: frm.doc.name,
                                content: message
                            }
                        },
                        callback: () => frm.reload_doc()
                    });
                });
            });

            // Call button
            const call_btn = $(`<button class="btn btn-sm btn-primary ml-2">
                <i class="fa fa-phone"></i> Call
            </button>`).on('click', () => {
                frappe.db.get_doc('Lead', frm.doc.name).then(doc => {
                    let phone = doc.phone || doc.mobile_no || "Not available";
                    let message = `📞 <b>${full_name}</b> called <b>${phone}</b>.`;
                    frappe.call({
                        method: "frappe.client.insert",
                        args: {
                            doc: {
                                doctype: "Comment",
                                comment_type: "Comment",
                                reference_doctype: "Lead",
                                reference_name: frm.doc.name,
                                content: message
                            }
                        },
                        callback: () => frm.reload_doc()
                    });
                });
            });

            email_btn.after(call_btn).after(whatsapp_btn);
            frm.timeline.custom_buttons_added = true;
        }, 600);
    }
});

function render_gst_tax_table(frm) {
    if (!frm.doc.items || !frm.doc.taxes) {
        if (frm.fields_dict.gst_tax_table) {
            frm.fields_dict.gst_tax_table.$wrapper.html('');
        }
        return;
    }

    // Step 1: Build tax data for each item
    const item_tax_map = {};
    const item_data = {};

    // Map each item_code to its data, including the item_name for display
    frm.doc.items.forEach(item => {
        item_data[item.item_code] = { // The key is the item_code for all logic
            price: item.amount || 0,
            item_name: item.item_name || item.item_code, // The item_name is stored for display purposes
            taxes: []
        };
    });

    frm.doc.taxes.forEach(tax => {
        if (!tax.item_wise_tax_detail) return;

        try {
            const tax_details = JSON.parse(tax.item_wise_tax_detail);
            for (const item_code in tax_details) {
                if (!item_data[item_code]) continue;

                const [tax_rate, tax_amount] = tax_details[item_code];
                item_data[item_code].taxes.push({
                    charge_type: tax.charge_type,
                    account_head: tax.account_head,
                    rate: tax_rate,
                    amount: tax_amount,
                    tax_index: frm.doc.taxes.indexOf(tax) // Store tax index for updates
                });
            }
        } catch (e) {
            console.error('Invalid item_wise_tax_detail JSON', e);
        }
    });

    // Step 2: Build the HTML table with editable tax rates
    let html = `
    <h4>Sales Taxes and Charges</h4>
    <table class="table table-bordered" style="font-size: 13px;">
        <thead>
            <tr>
                <th style="width: 5%;">NO.</th>
                <th style="width: 45%;">Item Name</th>
                <th style="width: 10%;">Tax Rate (%)</th>
                <th style="width: 10%;">Tax Amount (INR)</th>
                <th style="width: 10%;">Product Price (INR)</th>
                <th style="width: 20%;">Item Total (INR)</th>
            </tr>
        </thead>
        <tbody>
    `;

    let row_no = 1;
    let overall_product_total = 0;
    let overall_tax_total = 0;

    for (const item_code in item_data) {
        const item = item_data[item_code];
        const price = item.price;
        const taxes = item.taxes;
        const total_tax = taxes.reduce((sum, t) => sum + t.amount, 0);
        const item_total = price + total_tax;

        taxes.forEach((tax_row, index) => {
            // Create unique ID for each editable tax rate input
            const input_id = `tax_rate_${tax_row.tax_index}_${item_code}`;

            html += `<tr>
                <td>${row_no++}</td>
                <td>${item.item_name}</td>
                <td>
                    <input type="number"
                          id="${input_id}"
                          class="editable-tax-rate form-control"
                          value="${tax_row.rate.toFixed(2)}"
                          data-tax-index="${tax_row.tax_index}"
                          data-item-code="${item_code}"
                          data-item-price="${price}"
                          style="width: 80px; font-size: 12px; padding: 2px 5px;"
                          step="0.01"
                          min="0"
                          max="100">
                </td>
                <td class="tax-amount-cell" id="tax_amount_${tax_row.tax_index}_${item_code}">₹ ${tax_row.amount.toFixed(2)}</td>
                <td>${index === 0 ? `₹ ${price.toFixed(2)}` : ''}</td>
                <td class="item-total-cell" data-item-code="${item_code}">${index === taxes.length - 1 ? `<b>₹ ${item_total.toFixed(2)}</b>` : ''}</td>
            </tr>`;
        });

        overall_product_total += price;
        overall_tax_total += total_tax;
    }

    const grand_total = overall_product_total + overall_tax_total;

    html += `
        </tbody>
    </table>
    <div style="margin-top: 15px; font-size: 14px; text-align: right;">
        <strong>Total Product Price:</strong> <span id="total-product-price">₹ ${overall_product_total.toFixed(2)}</span><br>
        <strong>Total Taxes and Charges:</strong> <span id="total-tax-amount">₹ ${overall_tax_total.toFixed(2)}</span><br>
        <strong>Grand Total:</strong> <span id="grand-total">₹ ${grand_total.toFixed(2)}</span>
    </div>
    `;

    if (frm.fields_dict.gst_tax_table) {
        frm.fields_dict.gst_tax_table.$wrapper.html(html);

        // Add event listeners for editable tax rates
        setTimeout(() => {
            $('.editable-tax-rate').on('input change', function() {
                const new_rate = parseFloat($(this).val()) || 0;
                const tax_index = parseInt($(this).data('tax-index'));
                const item_code = $(this).data('item-code'); // Retrieve the item_code for calculations
                const item_price = parseFloat($(this).data('item-price'));

                // Calculate new tax amount based on new rate
                const new_tax_amount = (item_price * new_rate) / 100;

                // Update the tax amount in the table
                $(`#tax_amount_${tax_index}_${item_code}`).text(`₹ ${new_tax_amount.toFixed(2)}`);

                // Update the underlying tax document using the item_code
                if (frm.doc.taxes[tax_index] && frm.doc.taxes[tax_index].item_wise_tax_detail) {
                    try {
                        const tax_details = JSON.parse(frm.doc.taxes[tax_index].item_wise_tax_detail);
                        if (tax_details[item_code]) { // Use item_code as the key to find the correct tax
                            tax_details[item_code][0] = new_rate; // Update rate
                            tax_details[item_code][1] = new_tax_amount; // Update amount
                            frm.doc.taxes[tax_index].item_wise_tax_detail = JSON.stringify(tax_details);
                        }
                    } catch (e) {
                        console.error('Error updating tax details', e);
                    }
                }

                // Recalculate totals
                recalculate_totals(frm);
            });
        }, 100);
    }
}

function recalculate_totals(frm) {
    let total_product_price = 0;
    let total_tax_amount = 0;

    // Calculate totals from all items
    const item_totals = {};

    frm.doc.items.forEach(item => {
        total_product_price += item.amount || 0;
        item_totals[item.item_code] = {
            price: item.amount || 0,
            total_tax: 0
        };
    });

    // Calculate tax totals
    $('.editable-tax-rate').each(function() {
        const item_code = $(this).data('item-code');
        const item_price = parseFloat($(this).data('item-price'));
        const tax_rate = parseFloat($(this).val()) || 0;
        const tax_amount = (item_price * tax_rate) / 100;

        total_tax_amount += tax_amount;
        if (item_totals[item_code]) {
            item_totals[item_code].total_tax += tax_amount;
        }
    });

    // Update item totals in the table
    for (const item_code in item_totals) {
        const item_total = item_totals[item_code].price + item_totals[item_code].total_tax;
        $(`.item-total-cell[data-item-code="${item_code}"]`).html(`<b>₹ ${item_total.toFixed(2)}</b>`);
    }

    // Update summary totals
    const grand_total = total_product_price + total_tax_amount;
    $('#total-product-price').text(`₹ ${total_product_price.toFixed(2)}`);
    $('#total-tax-amount').text(`₹ ${total_tax_amount.toFixed(2)}`);
    $('#grand-total').text(`₹ ${grand_total.toFixed(2)}`);
}

// Enhanced Frappe Hooks
frappe.ui.form.on("Quotation", {
    refresh(frm) {
        render_gst_tax_table(frm);
    },

    // AUTO-REFRESH ON TAX CATEGORY CHANGE (without saving)
    tax_category(frm) {
        if (frm.doc.tax_category) {
            // First, get the appropriate Sales Taxes and Charges Template based on tax category
            frappe.call({
                method: "frappe.client.get_list",
                args: {
                    doctype: "Sales Taxes and Charges Template",
                    filters: {
                        "tax_category": frm.doc.tax_category,
                        "disabled": 0
                    },
                    fields: ["name", "title"],
                    limit: 1
                },
                callback: function(r) {
                    if (r.message && r.message.length > 0) {
                        // Set the taxes and charges template
                        frm.set_value("taxes_and_charges", r.message[0].name);

                        // Trigger the taxes_and_charges event to load the template
                        frm.trigger("taxes_and_charges");
                    } else {
                        // If no template found, clear the field
                        frm.set_value("taxes_and_charges", "");
                        frm.clear_table("taxes");
                        frm.refresh_field("taxes");
                        render_gst_tax_table(frm);
                    }
                }
            });
        } else {
            // If tax category is cleared, clear the template and taxes
            frm.set_value("taxes_and_charges", "");
            frm.clear_table("taxes");
            frm.refresh_field("taxes");
            render_gst_tax_table(frm);
        }
    },

    // Trigger when taxes and charges template changes
    taxes_and_charges(frm) {
        if (frm.doc.taxes_and_charges) {
            // Load the template and apply it to the taxes table
            frappe.call({
                method: "erpnext.controllers.accounts_controller.get_taxes_and_charges",
                args: {
                    "master_doctype": "Sales Taxes and Charges Template",
                    "master_name": frm.doc.taxes_and_charges
                },
                callback: function(r) {
                    if (r.message) {
                        // Clear existing taxes
                        frm.clear_table("taxes");

                        // Add new taxes from template
                        r.message.forEach(function(tax) {
                            let tax_row = frm.add_child("taxes");
                            Object.assign(tax_row, tax);
                        });

                        // Refresh the taxes field and recalculate
                        frm.refresh_field("taxes");

                        // Calculate taxes for all items
                        frm.trigger("calculate_taxes_and_totals");

                        // Render the custom tax table after calculation
                        setTimeout(() => {
                            render_gst_tax_table(frm);
                        }, 500);
                    }
                }
            });
        } else {
            // If template is cleared, clear taxes and refresh table
            frm.clear_table("taxes");
            frm.refresh_field("taxes");
            render_gst_tax_table(frm);
        }
    },

    items_add(frm) {
        render_gst_tax_table(frm);
    },
    items_remove(frm) {
        render_gst_tax_table(frm);
    },
    taxes_add(frm) {
        render_gst_tax_table(frm);
    },
    taxes_remove(frm) {
        render_gst_tax_table(frm);
    },
    gst_tax_type(frm) {
        render_gst_tax_table(frm);
    },
    validate(frm) {
        render_gst_tax_table(frm);
    }
});

