frappe.ui.form.on('Lead', {
    refresh(frm) {
        if (frm.doc.name && frm.doc.docstatus !== 2) {
            setTimeout(() => {
                // Remove duplicates
                const actionItems = document.querySelectorAll('a.dropdown-item');
                actionItems.forEach((item) => {
                    const text = item.innerText.trim();
                    if (text === 'Add to Prospect' || text === 'Add to Opportunity') {
                        item.remove();
                    }
                });

                if (!frm._opportunity_button_added) {
                    frm.page.add_action_item('Add to Opportunity', function () {
                        // Create via server call - most reliable method
                        frappe.call({
                            method: 'frappe.client.insert',
                            args: {
                                doc: {
                                    doctype: 'Opportunity',
                                    opportunity_from: 'Lead',
                                    party_name: frm.doc.name, // This will be the Lead ID
                                    customer_name: frm.doc.lead_name || frm.doc.company_name,
                                    contact_email: frm.doc.email_id,
                                    contact_mobile: frm.doc.mobile_no,
                                    contact_person: frm.doc.lead_name,
                                    source: frm.doc.source,
                                    territory: frm.doc.territory
                                }
                            },
                            callback: function(response) {
                                if (response.message) {
                                    frappe.show_alert({
                                        message: 'Opportunity created with Lead ID: ' + frm.doc.name,
                                        indicator: 'green'
                                    });
                                    // Open the created opportunity
                                    frappe.set_route('Form', 'Opportunity', response.message.name);
                                }
                            }
                        });
                    });
                    frm._opportunity_button_added = true;
                }
            }, 500);
        }
    }
});

