            // This is the selector that the diagnostic test PROVED is correct for your system.
            const plus_button = $("button[data-doctype='Opportunity']");

            // Check if the button was found.
            if (plus_button.length > 0) {
                // Remove any old click actions to prevent any possible conflicts.
                plus_button.off('click');

