function fetch_sales_person_full_name(frm) {
  const user_id = frm.doc.custom_sales_person;

  if (!user_id) {
    frm.set_value("custom_sales_person_name", "");
    return;
  }

  frappe.call({
    method: "frappe.client.get_value",
    args: {
      doctype: "User",
      filters: { name: user_id },
      fieldname: "full_name"
    },
    callback: function(response) {
      if (response.message) {
        frm.set_value("custom_sales_person_name", response.message.full_name);
      }
    }
  });
}

