        // Find the New Task button area and add our button
        let task_area = $(frm.fields_dict.activities_tab.wrapper).find('.timeline-new-task');
        if (task_area.length === 0) {
            // If not found, add to the activities section
            $(frm.fields_dict.activities_tab.wrapper).find('.timeline-actions').prepend(follow_up_btn);
        } else {
            task_area.after(follow_up_btn);
        }
    }
}

// Global function to create follow up dialog
window.create_follow_up_dialog = function(opportunity_name) {
    let dialog = new frappe.ui.Dialog({
        title: __('Create Follow Up Task'),
        fields: [
            {
                fieldname: 'subject',
                label: __('Subject'),
                fieldtype: 'Data',
                reqd: 1,
                default: `Follow up for Opportunity: ${opportunity_name}`
            },
            {
                fieldname: 'follow_up_date',
                label: __('Follow Up Date'),
                fieldtype: 'Date',
                reqd: 1,
                default: frappe.datetime.get_today()
            },
            {
                fieldname: 'follow_up_type',
                label: __('Follow Up Type'),
                fieldtype: 'Select',
                options: 'Phone\nWhatsApp\nEmail\nMeeting',
                reqd: 1,
                default: 'Phone'
            },
            {
                fieldname: 'contact_with',
                label: __('Contact With'),
                fieldtype: 'Data',
                reqd: 1,
                description: 'Enter contact person name/phone/email'
            },
            {
                fieldname: 'next_follow_up_date',
                label: __('Next Follow Up Date'),
                fieldtype: 'Date',
                description: 'Optional: When should the next follow up be scheduled?'
            },
            {
                fieldname: 'priority',
                label: __('Priority'),
                fieldtype: 'Select',
                options: 'Low\nMedium\nHigh',
                default: 'Medium'
            },
            {
                fieldname: 'assigned_to',
                label: __('Assigned To'),
                fieldtype: 'Link',
                options: 'User',
                reqd: 1,
                default: frappe.session.user
            },
            {
                fieldname: 'description',
                label: __('Additional Notes'),
                fieldtype: 'Text'
            }
        ],
        primary_action_label: __('Create Follow Up'),
        primary_action: function(values) {
            create_follow_up_task(values, opportunity_name, dialog);
        },
        secondary_action_label: __('Cancel')
    });

    // Auto-set priority and help text based on follow up type
    dialog.fields_dict.follow_up_type.$input.on('change', function() {
        let type = dialog.get_value('follow_up_type');
        let priority = 'Medium';
        let help_text = '';

        if (type === 'Phone') {
            priority = 'High';
            help_text = 'Enter phone number or contact person name';
        } else if (type === 'Email') {
            priority = 'Medium';
            help_text = 'Enter email address or contact person name';
        } else if (type === 'WhatsApp') {
            priority = 'Low';
            help_text = 'Enter WhatsApp number';
        } else if (type === 'Meeting') {
            priority = 'High';
            help_text = 'Enter meeting location or person to meet';
        }

        dialog.set_value('priority', priority);
        dialog.set_df_property('contact_with', 'description', help_text);
    });

    // Auto-suggest next follow up date
    dialog.fields_dict.follow_up_date.$input.on('change', function() {
        let follow_up_date = dialog.get_value('follow_up_date');
        if (follow_up_date && !dialog.get_value('next_follow_up_date')) {
            let next_date = frappe.datetime.add_days(follow_up_date, 7);
            dialog.set_value('next_follow_up_date', next_date);
        }
    });

    dialog.show();
};

function create_follow_up_task(values, opportunity_name, dialog) {
    frappe.call({
        method: 'frappe.client.insert',
        args: {
            doc: {
                doctype: 'Task',
                subject: values.subject,
                description: values.description || `Follow up via ${values.follow_up_type} with ${values.contact_with}`,
                priority: values.priority,
                status: 'Open',
                exp_end_date: values.follow_up_date,

                // Custom follow up fields
                is_follow_up_task: 1,
                follow_up_date: values.follow_up_date,
                follow_up_type: values.follow_up_type,
                contact_with: values.contact_with,
                next_follow_up_date: values.next_follow_up_date,
                opportunity_ref: opportunity_name
            }
        },
        callback: function(r) {
            if (r.message) {
                // Assign the task to the selected user
                frappe.call({
                    method: 'frappe.desk.form.assign_to.add',
                    args: {
                        doctype: 'Task',
                        name: r.message.name,
                        assign_to: [values.assigned_to],
                        description: values.subject
                    },
                    callback: function() {
                        frappe.show_alert({
                            message: __('Follow up task created and assigned successfully'),
                            indicator: 'green'
                        });

                        dialog.hide();

                        // Refresh the current form to show the new task in timeline
                        cur_frm.reload_doc();
                    }
                });
            }
        }
    });
}

frappe.ui.form.on('Task', {
    refresh: function(frm) {
        if (frm.doc.is_follow_up_task) {
            customize_follow_up_task_form(frm);
        }
    },

    follow_up_type: function(frm) {
        // Set priority based on follow up type
        if (frm.doc.follow_up_type === 'Phone' || frm.doc.follow_up_type === 'Meeting') {
            frm.set_value('priority', 'High');
        } else if (frm.doc.follow_up_type === 'Email') {
            frm.set_value('priority', 'Medium');
        } else if (frm.doc.follow_up_type === 'WhatsApp') {
            frm.set_value('priority', 'Low');
        }
    },

    follow_up_date: function(frm) {
        // Set expected end date to follow up date
        if (frm.doc.follow_up_date) {
            frm.set_value('exp_end_date', frm.doc.follow_up_date);

            // Auto-suggest next follow up date if not set
            if (!frm.doc.next_follow_up_date) {
                let next_date = frappe.datetime.add_days(frm.doc.follow_up_date, 7);
                frm.set_value('next_follow_up_date', next_date);
            }
        }
    },

    status: function(frm) {
        // When task is completed, offer to create next follow up
        if (frm.doc.status === 'Completed' && frm.doc.is_follow_up_task && frm.doc.next_follow_up_date) {
            setTimeout(function() {
                offer_next_follow_up(frm);
            }, 1000);
        }
    }
});

function customize_follow_up_task_form(frm) {
    // Add custom buttons for follow up tasks
    frm.add_custom_button(__('Create Next Follow Up'), function() {
        create_next_follow_up(frm);
    }, __('Follow Up Actions'));

    frm.add_custom_button(__('Mark as Contacted'), function() {
        frm.set_value('status', 'Completed');
        frm.save();
        frappe.show_alert('Task marked as completed');
    }, __('Follow Up Actions'));

    // Show follow up details prominently
    frm.set_df_property('follow_up_section', 'collapsible', 0);
}

function offer_next_follow_up(frm) {
    frappe.confirm(
        __('Task completed! Would you like to create the next follow up for {0}?', 
          [frappe.datetime.str_to_user(frm.doc.next_follow_up_date)]),
        function() {
            create_next_follow_up(frm);
        }
    );
}

function create_next_follow_up(frm) {
    frappe.new_doc('Task', {
        subject: `Follow up - ${frm.doc.contact_with}`,
        is_follow_up_task: 1,
        follow_up_date: frm.doc.next_follow_up_date,
        follow_up_type: frm.doc.follow_up_type,
        contact_with: frm.doc.contact_with,
        opportunity_ref: frm.doc.opportunity_ref,
        priority: frm.doc.priority,
        description: `Continuation of follow up from task: ${frm.doc.name}`
    });
}

