function override_new_task_button(frm) {
    // Find all New Task buttons and override them
    $(frm.wrapper).find('button').each(function() {
        if ($(this).text().trim() === 'New Task') {
            $(this).off('click').on('click', function(e) {
                e.preventDefault();
                e.stopPropagation();
                show_custom_follow_up_dialog(frm);
                return false;
            });
        }
    });

    // Also check for any timeline buttons
    $(frm.wrapper).on('click', 'button:contains("New Task")', function(e) {
        e.preventDefault();
        e.stopPropagation();
        show_custom_follow_up_dialog(frm);
        return false;
    });
}

function show_custom_follow_up_dialog(frm) {
    let dialog = new frappe.ui.Dialog({
        title: __('New Task'),
        fields: [
            {
                fieldname: 'task_type',
                label: __('Task Type'),
                fieldtype: 'Select',
                options: 'Regular Task\nFollow Up Task',
                default: 'Follow Up Task',
                onchange: function() {
                    let task_type = dialog.get_value('task_type');
                    toggle_follow_up_fields(dialog, task_type === 'Follow Up Task');
                }
            },
            {
                fieldname: 'section_break_1',
                fieldtype: 'Section Break'
            },
            {
                fieldname: 'date',
                label: __('Date'),
                fieldtype: 'Date',
                default: frappe.datetime.get_today(),
                reqd: 1
            },
            {
                fieldname: 'assigned_to',
                label: __('Assigned To'),
                fieldtype: 'Link',
                options: 'User',
                default: frappe.session.user,
                reqd: 1
            },

            // Follow-up specific fields
            {
                fieldname: 'follow_up_section',
                fieldtype: 'Section Break',
                label: __('Follow-up Details'),
                depends_on: 'eval:doc.task_type=="Follow Up Task"'
            },
            {
                fieldname: 'follow_up_type',
                label: __('Follow Up Type'),
                fieldtype: 'Select',
                options: 'Phone\nWhatsApp\nEmail\nMeeting',
                depends_on: 'eval:doc.task_type=="Follow Up Task"',
                mandatory_depends_on: 'eval:doc.task_type=="Follow Up Task"'
            },
            {
                fieldname: 'contact_with',
                label: __('Contact With'),
                fieldtype: 'Data',
                depends_on: 'eval:doc.task_type=="Follow Up Task"',
                mandatory_depends_on: 'eval:doc.task_type=="Follow Up Task"',
                description: __('Enter contact person name, phone number, or email')
            },
            {
                fieldname: 'next_follow_up_date',
                label: __('Next Follow Up Date'),
                fieldtype: 'Date',
                depends_on: 'eval:doc.task_type=="Follow Up Task"'
            },
            {
                fieldname: 'priority',
                label: __('Priority'),
                fieldtype: 'Select',
                options: 'Low\nMedium\nHigh',
                default: 'Medium',
                depends_on: 'eval:doc.task_type=="Follow Up Task"'
            },

            // Description (like original)
            {
                fieldname: 'description_section',
                fieldtype: 'Section Break'
            },
            {
                fieldname: 'description',
                fieldtype: 'Text Editor',
                reqd: 1
            }
        ],
        primary_action_label: __('Create'),
        primary_action: function(values) {
            create_task_with_follow_up(values, frm, dialog);
        },
        secondary_action_label: __('Cancel')
    });

    // Set up field behaviors
    setup_field_behaviors(dialog);

    dialog.show();

    // Focus on description like original
    setTimeout(function() {
        if (dialog.fields_dict.description && dialog.fields_dict.description.editor) {
            dialog.fields_dict.description.editor.focus();
        }
    }, 500);
}

function setup_field_behaviors(dialog) {
    // Auto-set priority based on follow up type
    dialog.fields_dict.follow_up_type.$input.on('change', function() {
        let type = dialog.get_value('follow_up_type');
        let priority = 'Medium';

        if (type === 'Phone' || type === 'Meeting') {
            priority = 'High';
        } else if (type === 'Email') {
            priority = 'Medium';
        } else if (type === 'WhatsApp') {
            priority = 'Low';
        }

        dialog.set_value('priority', priority);

        // Update contact field description
        update_contact_field_description(dialog, type);
    });

    // Auto-suggest next follow up date
    dialog.fields_dict.date.$input.on('change', function() {
        let follow_up_date = dialog.get_value('date');
        if (follow_up_date && !dialog.get_value('next_follow_up_date')) {
            let next_date = frappe.datetime.add_days(follow_up_date, 7);
            dialog.set_value('next_follow_up_date', next_date);
        }
    });

    // Auto-generate description
    dialog.fields_dict.contact_with.$input.on('change', function() {
        update_description_if_empty(dialog);
    });
}

function update_contact_field_description(dialog, type) {
    let description = 'Enter contact person name, phone number, or email';

    if (type === 'Phone') {
        description = 'Enter phone number or contact person name';
    } else if (type === 'WhatsApp') {
        description = 'Enter WhatsApp number';
    } else if (type === 'Email') {
        description = 'Enter email address';
    } else if (type === 'Meeting') {
        description = 'Enter person to meet or meeting location';
    }

    dialog.set_df_property('contact_with', 'description', __(description));
}

function update_description_if_empty(dialog) {
    let contact = dialog.get_value('contact_with');
    let type = dialog.get_value('follow_up_type');
    let task_type = dialog.get_value('task_type');

    if (contact && type && task_type === 'Follow Up Task' && !dialog.get_value('description')) {
        let auto_desc = `${type} follow-up with ${contact}`;
        dialog.set_value('description', auto_desc);
    }
}

function toggle_follow_up_fields(dialog, show) {
    // This function will be called when task type changes
    // The depends_on conditions will handle the field visibility
    dialog.refresh();
}

function create_task_with_follow_up(values, frm, dialog) {
    let task_doc = {
        doctype: 'Task',
        subject: values.description ? values.description.substring(0, 140) : 'New Task',
        description: values.description,
        status: 'Open',
        exp_end_date: values.date,
        priority: values.priority || 'Medium'
    };

    // Add follow-up fields if it's a follow-up task
    if (values.task_type === 'Follow Up Task') {
        task_doc.is_follow_up_task = 1;
        task_doc.follow_up_date = values.date;
        task_doc.follow_up_type = values.follow_up_type;
        task_doc.contact_with = values.contact_with;
        task_doc.next_follow_up_date = values.next_follow_up_date;
        task_doc.related_opportunity = frm.docname;

        // Better subject for follow-up tasks
        if (values.contact_with && values.follow_up_type) {
            task_doc.subject = `${values.follow_up_type} follow-up: ${values.contact_with}`;
        }
    }

    frappe.call({
        method: 'frappe.client.insert',
        args: {
            doc: task_doc
        },
        callback: function(r) {
            if (r.message) {
                // Assign task
                frappe.call({
                    method: 'frappe.desk.form.assign_to.add',
                    args: {
                        doctype: 'Task',
                        name: r.message.name,
                        assign_to: [values.assigned_to],
                        description: values.description || task_doc.subject
                    },
                    callback: function() {
                        frappe.show_alert({
                            message: __('Task created and assigned successfully'),
                            indicator: 'green'
                        });

                        dialog.hide();

                        // Refresh the opportunity to show new task
                        frm.reload_doc();
                    }
                });
            }
        },
        error: function(r) {
            frappe.msgprint({
                title: __('Error'),
                message: __('Failed to create task. Please try again.'),
                indicator: 'red'
            });
        }
    });
}

