frappe.ui.form.on('Opportunity', {
	refresh(frm) {
		class UIElementController {
    constructor() {
        this.hiddenElements = new Map();
    }

    hideElement(selector, method = 'display') {
        try {
            const element = document.querySelector(selector);
            if (!element) {
                console.warn(`Element not found: ${selector}`);
                return false;
            }

            // Store original state for restoration
            if (!this.hiddenElements.has(selector)) {
                this.hiddenElements.set(selector, {
                    originalDisplay: getComputedStyle(element).display,
                    originalVisibility: getComputedStyle(element).visibility,
                    originalOpacity: getComputedStyle(element).opacity
                });
            }

            switch(method) {
                case 'display':
                    element.style.display = 'none';
                    break;
                case 'visibility':
                    element.style.visibility = 'hidden';
                    break;
                case 'opacity':
                    element.style.opacity = '0';
                    element.style.transition = 'opacity 0.3s ease';
                    break;
                case 'class':
                    element.classList.add('hidden-element');
                    break;
            }

            element.setAttribute('aria-hidden', 'true');
            return true;

        } catch (error) {
            console.error(`Error hiding element ${selector}:`, error);
            return false;
        }
    }

    showElement(selector) {
        try {
            const element = document.querySelector(selector);
            const originalState = this.hiddenElements.get(selector);

            if (element && originalState) {
                element.style.display = originalState.originalDisplay;
                element.style.visibility = originalState.originalVisibility;
                element.style.opacity = originalState.originalOpacity;
                element.classList.remove('hidden-element');
                element.setAttribute('aria-hidden', 'false');
            }
        } catch (error) {
            console.error(`Error showing element ${selector}:`, error);
        }
    }
}

