frappe.ui.form.on('Opportunity', {
  refresh: function(frm) {
    frm.events.add_custom_buttons(frm);
  },

  add_custom_buttons: function(frm) {
    setTimeout(() => {
      const timeline_area = frm.timeline?.wrapper;
      if (!timeline_area || frm.timeline.custom_buttons_added) return;

      const email_btn = timeline_area.find('.btn:contains("New Email")');
      if (!email_btn.length) return;

      // Only add the display span if it is not present
      if (!timeline_area.find('#contact-number-display').length) {
        email_btn.parent().append(`<span id="contact-number-display" style="margin-left:16px;font-weight:bold;"></span>`);
      }

      // WhatsApp button
      const whatsapp_btn = $(`<button class="btn btn-sm btn-success ml-2">
        <i class="fa fa-whatsapp"></i> Whatsapp
      </button>`).on('click', async function() {
        const phone = await get_priority_phone(frm);
        $('#contact-number-display').text(`Phone: ${phone}`);
        log_followup_interaction(frm, 'Whatsapp', phone);
      });

      // Call button
      const call_btn = $(`<button class="btn btn-sm btn-primary ml-2">
        <i class="fa fa-phone"></i> Phone
      </button>`).on('click', async function() {
        const phone = await get_priority_phone(frm);
        $('#contact-number-display').text(`Phone: ${phone}`);
        log_followup_interaction(frm, 'Phone', phone);
      });

      email_btn.after(call_btn).after(whatsapp_btn);
      frm.timeline.custom_buttons_added = true;
    }, 600);
  }
});

// Priority phone fetcher (Lead, Opportunity.contact_mobile, Opportunity.phone)
async function get_priority_phone(frm) {
  let phone = "";

  // 1. Check Lead
  if (frm.doc.lead) {
    try {
      let lead = await frappe.db.get_doc('Lead', frm.doc.lead);
      phone = lead.phone || lead.mobile_no || "";
    } catch (error) {
      phone = "";
    }
  }

  // 2. Check Opportunity.contact_mobile
  if (!phone && frm.doc.contact_mobile) {
    phone = frm.doc.contact_mobile;
  }

  // 3. Check Opportunity.phone
  if (!phone && frm.doc.phone) {
    phone = frm.doc.phone;
  }

  return phone || "Unknown";
}

function log_followup_interaction(frm, type, phone) {
  const full_name = frappe.user.full_name();
  const today = frappe.datetime.get_today();

  frappe.call({
    method: "frappe.client.insert",
    args: {
      doc: {
        doctype: "Comment",
        comment_type: "Comment",
        reference_doctype: "Opportunity",
        reference_name: frm.doc.name,
        content: `🟢 <b>${full_name}</b> contacted via <b>${type}</b> at <b>${phone}</b>.`
      }
    }
  });

  frm.add_child('follow_up_activities', {
    follow_up_type: type,
    follow_up_date: today,
    description: `${full_name} contacted via ${type} at ${phone}`
  });
  frm.refresh_field('follow_up_activities');
  frm.save();
}

