            frm.page.set_inner_btn_group_as_primary(__('Create'));
        }

        // Setup connections functionality (clean version)
        setTimeout(function() {
            setup_clean_connections(frm);
        }, 1500);

        // Re-setup when switching to Connections tab
        frm.page.wrapper.find('a[data-toggle="tab"]').on('shown.bs.tab', function(e) {
            let tab_text = $(e.target).text().trim();
            if (tab_text === 'Connections') {
                setTimeout(function() {
                    setup_clean_connections(frm);
                }, 800);
            }
        });
    }
});

function setup_clean_connections(frm) {
    // Find quotation text elements and make them clickable (no styling changes)
    frm.page.wrapper.find('*').filter(function() {
        return $(this).text().trim() === 'Quotation' && $(this).children().length === 0;
    }).each(function() {
        let quotation_element = $(this);

        // Skip if already processed
        if (quotation_element.hasClass('quotation-clickable')) {
            return;
        }

        // Make it clickable without any visual changes
        quotation_element.addClass('quotation-clickable');
        quotation_element.css('cursor', 'pointer');

        // Add click handler
        quotation_element.on('click', function(e) {
            e.preventDefault();
            create_quotation_from_opportunity(frm);
        });
    });

    // Also handle any buttons near quotation elements
    frm.page.wrapper.find('*:contains("Quotation")').each(function() {
        let container = $(this);
        let text = container.text().toLowerCase();

        // Only process if it's specifically quotation (not request for quotation, etc.)
        if (text === 'quotation' || (text.includes('quotation') && !text.includes('request') && !text.includes('supplier'))) {

            // Find buttons within this container
            container.find('button, .btn, a').each(function() {
                let btn = $(this);

                // Skip if already processed
                if (btn.hasClass('quotation-btn-processed')) {
                    return;
                }

                btn.addClass('quotation-btn-processed');

                // Override click handler
                btn.off('click.quotation').on('click.quotation', function(e) {
                    e.preventDefault();
                    e.stopPropagation();
                    create_quotation_from_opportunity(frm);
                    return false;
                });
            });
        }
    });
}

function create_quotation_from_opportunity(frm) {
    if (!frm.doc || !frm.doc.name) {
        frappe.msgprint(__('Please save the opportunity first'));
        return;
    }

    // Check if form has unsaved changes and save if needed
    if (frm.is_dirty()) {
        frappe.msgprint({
            title: __('Saving Opportunity'),
            message: __('Saving changes before creating quotation...'),
            indicator: 'blue'
        });

        // Save the form first, then create quotation
        frm.save().then(function() {
            create_quotation_after_save(frm);
        }).catch(function() {
            frappe.msgprint({
                title: __('Error'),
                message: __('Please save the opportunity manually and try again.'),
                indicator: 'red'
            });
        });
    } else {
        // Form is already saved, proceed directly
        create_quotation_after_save(frm);
    }
}

function create_quotation_after_save(frm) {
    frappe.show_alert({
        message: __('Creating Quotation...'),
        indicator: 'blue'
    }, 3);

    frappe.model.open_mapped_doc({
        method: "erpnext.crm.doctype.opportunity.opportunity.make_quotation",
        frm: frm,
        args: {
            source_name: frm.doc.name
        },
        callback: function(r) {
            if (r.message) {
                frappe.show_alert({
                    message: __('Quotation {0} created successfully!', [r.message.name]),
                    indicator: 'green'
                }, 5);

                // Refresh to show the new connection
                setTimeout(function() {
                    frm.reload_doc();
                }, 2000);
            }
        },
        error: function(r) {
            frappe.show_alert({
                message: __('Failed to create quotation. Please try again.'),
                indicator: 'red'
            }, 5);
        }
    });
}

