frappe.ui.form.on("Quotation", {
    // This is the core function that calculates GST based on the tax category.
    item_tax_category(frm) {
        if (!frm.doc.item_tax_category || !frm.doc.items) return;

        frm.doc.items.forEach(item => {
            // Reset GST values first
            item.cgst_rate = 0;
            item.cgst_amount = 0;
            item.sgst_rate = 0;
            item.sgst_amount = 0;
            item.igst_rate = 0;
            item.igst_amount = 0;

            if (frm.doc.item_tax_category === "In-State") {
                // Apply CGST 9% + SGST 9%
                item.cgst_rate = 9;
                item.sgst_rate = 9;
                item.cgst_amount = (item.amount || 0) * 0.09;
                item.sgst_amount = (item.amount || 0) * 0.09;
            } else if (frm.doc.item_tax_category === "Out-State") {
                // Apply IGST 18%
                item.igst_rate = 18;
                item.igst_amount = (item.amount || 0) * 0.18;
            } else if (frm.doc.item_tax_category === "No Tax") {
                // Leave all zero
            }
        });

        frm.refresh_field("items");
        frm.trigger("update_totals");
    },

    // This hook runs every time the form is loaded or refreshed.
    refresh(frm) {
        frm.trigger("update_totals");
    },

    // This is a custom function to calculate and update the total GST and Grand Total.
    update_totals(frm) {
        let total_gst = 0;
        let grand_total = flt(frm.doc.total);

        frm.doc.items.forEach(item => {
            total_gst += flt(item.cgst_amount) + flt(item.sgst_amount) + flt(item.igst_amount);
        });

        // Update the main document fields
        frm.set_value("total_taxes_and_charges", total_gst);
        frm.set_value("grand_total", grand_total + total_gst);
    }
});

