    amount: function(frm, cdt, cdn) {
        frm.trigger("update_gst_for_item", cdt, cdn);
        frm.trigger("update_totals");
    },

    // This hook fires when a user manually changes a GST rate.
    cgst_rate: function(frm, cdt, cdn) {
        frm.trigger("update_gst_amount", cdt, cdn);
        frm.trigger("update_totals");
    },
    sgst_rate: function(frm, cdt, cdn) {
        frm.trigger("update_gst_amount", cdt, cdn);
        frm.trigger("update_totals");
    },
    igst_rate: function(frm, cdt, cdn) {
        frm.trigger("update_gst_amount", cdt, cdn);
        frm.trigger("update_totals");
    },

    // Custom function to calculate GST amounts based on manual rate changes.
    update_gst_amount(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        let amount = flt(row.amount || 0);

        row.cgst_amount = amount * flt(row.cgst_rate || 0) / 100;
        row.sgst_amount = amount * flt(row.sgst_rate || 0) / 100;
        row.igst_amount = amount * flt(row.igst_rate || 0) / 100;

        frm.refresh_field("items");
    },

    // This function calculates GST from the tax category, but is separate from the manual override.
    update_gst_for_item(frm, cdt, cdn) {
        let row = locals[cdt][cdn];

        if (frm.doc.item_tax_category === "In-State") {
            row.cgst_rate = 9;
            row.sgst_rate = 9;
            row.igst_rate = 0;
        } else if (frm.doc.item_tax_category === "Out-State") {
            row.igst_rate = 18;
            row.cgst_rate = 0;
            row.sgst_rate = 0;
        } else {
            row.cgst_rate = 0;
            row.sgst_rate = 0;
            row.igst_rate = 0;
        }

        row.cgst_amount = flt(row.amount || 0) * flt(row.cgst_rate || 0) / 100;
        row.sgst_amount = flt(row.amount || 0) * flt(row.sgst_rate || 0) / 100;
        row.igst_amount = flt(row.amount || 0) * flt(row.igst_rate || 0) / 100;

        frm.refresh_field("items");
    }
});

