function recalc_row_gst(row) {
    let base_amount = row.amount || 0;

    // Calculate each tax
    row.cgst_amount = (base_amount * (row.cgst_rate || 0)) / 100;
    row.sgst_amount = (base_amount * (row.sgst_rate || 0)) / 100;
    row.igst_amount = (base_amount * (row.igst_rate || 0)) / 100;

    // Update child row values
    frappe.model.set_value(row.doctype, row.name, "cgst_amount", row.cgst_amount);
    frappe.model.set_value(row.doctype, row.name, "sgst_amount", row.sgst_amount);
    frappe.model.set_value(row.doctype, row.name, "igst_amount", row.igst_amount);
}

function recalc_totals_with_gst(frm) {
    let total_amount = 0;
    let total_gst = 0;

    (frm.doc.items || []).forEach(row => {
        recalc_row_gst(row);  

        total_amount += row.amount || 0;
        total_gst += (row.cgst_amount || 0) + (row.sgst_amount || 0) + (row.igst_amount || 0);
    });

    // Set GST-only field
    frm.set_value("total_gst", total_gst);

    // Set total with GST
    frm.set_value("total_with_gst", total_amount + total_gst);
}

