function recalc_item_gst(frm, row) {
    let base_amount = row.amount || (row.rate * row.qty) || 0;

    // reset all first
    row.custom_cgst_amount = row.custom_sgst_amount = row.custom_igst_amount = 0;
    row.custom_cgst_rate = row.custom_cgst_rate || 0;
    row.custom_sgst_rate = row.custom_sgst_rate || 0;
    row.custom_igst_rate = row.custom_igst_rate || 0;

    if (frm.doc.item_tax_category === "In-State") {
        // enable CGST/SGST, disable IGST
        row.custom_igst_rate = 0;
        row.custom_igst_amount = 0;

        row.custom_cgst_rate = row.custom_cgst_rate || 9;
        row.custom_sgst_rate = row.custom_sgst_rate || 9;

        row.custom_cgst_amount = (base_amount * row.custom_cgst_rate) / 100;
        row.custom_sgst_amount = (base_amount * row.custom_sgst_rate) / 100;

    } else if (frm.doc.item_tax_category === "Out-State") {
        // enable IGST, disable CGST/SGST
        row.custom_cgst_rate = 0;
        row.custom_sgst_rate = 0;
        row.custom_cgst_amount = 0;
        row.custom_sgst_amount = 0;

        row.custom_igst_rate = row.custom_igst_rate || 18;
        row.custom_igst_amount = (base_amount * row.custom_igst_rate) / 100;
    }
}

function update_item_field_permissions(frm) {
    frm.fields_dict["items"].grid.grid_rows.forEach(row => {
        let grid_row = row.doc;

        if (frm.doc.item_tax_category === "In-State") {
            // CGST & SGST editable, IGST read-only
            row.toggle_editable("custom_cgst_rate", true);
            row.toggle_editable("custom_sgst_rate", true);
            row.toggle_editable("custom_igst_rate", false);

        } else if (frm.doc.item_tax_category === "Out-State") {
            // IGST editable, CGST & SGST read-only
            row.toggle_editable("custom_cgst_rate", false);
            row.toggle_editable("custom_sgst_rate", false);
            row.toggle_editable("custom_igst_rate", true);
        }
    });
}

