frappe.ui.form.on('Opportunity', {
  refresh(frm) {
    // Doctypes to hide from the Connections area
    const HIDE = new Set(['Supplier Quotation', 'Request for Quotation']);

    // Hide function that works across Frappe/ERPNext versions
    const hideConnections = () => {
      const $root = frm.$wrapper; // strictly scoped to this form

      // Classic dashboard tiles (older/newer versions)
      $root.find('.document-link').each(function () {
        const $el = $(this);
        const dt =
          $el.attr('data-doctype') ||
          $el.find('.document-link-badge').attr('data-doctype') ||
          ($el.find('.badge-link').text() || '').trim();
        if (HIDE.has(dt)) {
          $el.remove();
        }
      });

      // Right sidebar “Connections” (v14/v15 style)
      $root.find('.form-sidebar .links li, .form-links li').each(function () {
        const txt = ($(this).find('.badge-link, a, span').first().text() || '').trim();
        const dt = $(this).attr('data-doctype') || txt;
        if (HIDE.has(dt)) {
          $(this).remove();
        }
      });
    };

    // Run once after initial render
    setTimeout(hideConnections, 300);

    // Re-run whenever the dashboard re-renders links
    if (frm.dashboard && !frm.dashboard.__hideConnPatched) {
      const orig = frm.dashboard.render_links?.bind(frm.dashboard);
      if (orig) {
        frm.dashboard.render_links = function () {
          const out = orig();
          hideConnections();
          return out;
        };
      }
      frm.dashboard.__hideConnPatched = true;
    }

    // As a fallback, watch briefly for DOM updates then stop (won’t affect other forms)
    if (!frm.__connObserver) {
      const observer = new MutationObserver(() => hideConnections());
      observer.observe(frm.$wrapper.get(0), { childList: true, subtree: true });
      frm.__connObserver = observer;
      // disconnect after a few seconds so it doesn’t linger
      setTimeout(() => {
        observer.disconnect();
        frm.__connObserver = null;
      }, 4000);
    }
  },
});

