        frm.set_df_property("custom_country_link", "options", ["", ...get_all_countries()].sort());
        frm.refresh_field("custom_country_link");
    },

    custom_country_link: function(frm) {
        if (frm.doc.custom_country_link) {
            load_states_for_country(frm, frm.doc.custom_country_link);
            frm.set_value("custom_state", ""); // reset state when country changes
            frm.set_value("city", "");  // reset city when country changes
        }
    },

    custom_state: function(frm) {
        if (frm.doc.custom_state) {
            load_cities_for_state(frm, frm.doc.custom_state);
            frm.set_value("city", ""); // reset city when state changes
        }
    }
});

// ============================================================================
// HELPER FUNCTION: LOAD STATES/PROVINCES FOR SELECTED COUNTRY
// ============================================================================
function load_states_for_country(frm, country_name) {
    let states_or_provinces = [];

    if (country_name === "India") {
        const indian_states = get_states_for_country("India");
        const union_territories = get_union_territories();
        states_or_provinces = [...indian_states, ...union_territories].sort();
    } else {
        states_or_provinces = get_states_for_country(country_name);
    }

    frm.set_df_property("custom_state", "options", ["", ...states_or_provinces]);
    frm.refresh_field("custom_state");

    if (!states_or_provinces.length) {
        frappe.show_alert({ message: `No states found for ${country_name}`, indicator: "orange" });
    }
}

// ============================================================================
// HELPER FUNCTION: LOAD CITIES FOR SELECTED STATE OR UNION TERRITORY
// ============================================================================
function load_cities_for_state(frm, state_or_ut_name) {
    let cities = [];

    // First check normal states
    cities = get_cities_for_state(state_or_ut_name);

    // If none found, check UTs (only for India)
    if ((!cities || !cities.length) && frm.doc.custom_country_link === "India") {
        cities = get_cities_for_union_territory(state_or_ut_name);
    }

    frm.set_df_property("city", "options", ["", ...cities].sort());
    frm.refresh_field("city");

    if (!cities.length) {
        frappe.show_alert({ message: `No cities found for ${state_or_ut_name}`, indicator: "orange" });
    }
}

