function update_latest_status(frm) {
    if (!frm.doc.follow_up_activities || frm.doc.follow_up_activities.length === 0) {
        if (frm.doc.latest_inquiry_status) {
            frm.doc.latest_inquiry_status = "";
            frm.refresh_field("latest_inquiry_status");
        }
        return;
    }

    let last_row = frm.doc.follow_up_activities[frm.doc.follow_up_activities.length - 1];
    if (!last_row || !last_row.inquiry_status) return;

    if (frm.doc.latest_inquiry_status !== last_row.inquiry_status) {
        frm.doc.latest_inquiry_status = last_row.inquiry_status;
        frm.refresh_field("latest_inquiry_status");
    }
}

