frappe.ui.form.on("Opportunity", {

    // 1️⃣ Before saving → fill contact person in follow-up table
    before_save(frm) {

        if (!frm.doc.follow_up_activities || !frm.doc.contact_person) return;

        frm.doc.follow_up_activities.forEach(row => {

            if (!row.contact_with) {
                row.contact_with = frm.doc.contact_person;
            }

        });

    },


    // 2️⃣ When contact person changes → update follow-up rows
    contact_person(frm) {

        if (!frm.doc.follow_up_activities) return;

        frm.doc.follow_up_activities.forEach(row => {

            row.contact_with = frm.doc.contact_person;

        });

        frm.refresh_field("follow_up_activities");

    },


    // 3️⃣ Add Create Quotation button
    refresh(frm) {

        if (!frm.custom_create_quotation_btn) {

            frm.add_custom_button("Create Quotation", function () {

                create_quotation_with_autosave(frm);

            }, "Create");

            frm.custom_create_quotation_btn = true;

        }

    }

});


// 4️⃣ Auto-save Opportunity before creating quotation
function create_quotation_with_autosave(frm) {

    if (frm.is_dirty()) {

        frappe.show_alert({
            message: "Saving Opportunity before creating Quotation...",
            indicator: "blue"
        });

        frm.save().then(() => {

            open_quotation(frm);

        });

    } else {

        open_quotation(frm);

    }

}


// 5️⃣ Open Quotation
function open_quotation(frm) {

    frappe.model.open_mapped_doc({

        method: "erpnext.crm.doctype.opportunity.opportunity.make_quotation",
        frm: frm

    });

}

$(document).on("app_ready", function() {
    frappe.router.on("change", function() {
        var route = frappe.get_route();
        if (route[0] === "query-report" && 
            route[1] === "Opportunity by sales person report") {

            setTimeout(function() {
                if (window.cur_report) {
                    cur_report.filters = cur_report.filters || [];

                    // Force inject user filter value
                    frappe.call({
                        method: "frappe.client.get_value",
                        args: {
                            doctype: "User",
                            filters: {name: frappe.session.user},
                            fieldname: ["name"]
                        },
                        callback: function(r) {
                            if (r && r.message) {
                                cur_report.set_filter_value(
                                    "user", 
                                    r.message.name
                                );
                                cur_report.refresh();
                            }
                        }
                    });
                }
            }, 1000);
        }
    });
});

