function toggle_custom_field(frm) {
    if (frm.doc.custom_email_type === "Custom") {
        frm.set_df_property('custom_email_body', 'hidden', 0);
    } else {
        frm.set_df_property('custom_email_body', 'hidden', 1);
    }
}
